<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Conway's Game of Life</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    color: #eee;
    font-family: 'Segoe UI', system-ui, sans-serif;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    overflow: hidden;
  }
  .container {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 16px;
  }
  h1 {
    font-size: 1.4rem;
    color: #e94560;
    letter-spacing: 2px;
    text-transform: uppercase;
  }
  canvas#life {
    border: 2px solid #16213e;
    background: #0f3460;
    cursor: crosshair;
    image-rendering: pixelated;
  }
  .controls {
    display: flex;
    gap: 10px;
    align-items: center;
  }
  button {
    padding: 8px 20px;
    border: none;
    border-radius: 6px;
    font-size: 0.9rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.15s ease;
    color: #fff;
  }
  button:hover { transform: translateY(-2px); filter: brightness(1.15); }
  button:active { transform: translateY(0); }
  #step { background: #e94560; }
  #play { background: #0f3460; border: 2px solid #e94560; }
  #random { background: #16213e; border: 2px solid #533483; }
  #clear { background: #1a1a2e; border: 2px solid #eee; color: #aaa; }
  .info { font-size: 0.75rem; color: #666; margin-top: 4px; }
</style>
</head>
<body>
<div class="container">
  <h1>Game of Life</h1>
  <canvas id="life"></canvas>
  <div class="controls">
    <button id="step">Step</button>
    <button id="play">Play ▸</button>
    <button id="random">Random</button>
    <button id="clear">Clear</button>
  </div>
  <div class="info" id="info"></div>
</div>

<script>
(function () {
  'use strict';

  const W = 60, H = 40;
  const CELL = 12;
  const CANVAS_W = W * CELL;
  const CANVAS_H = H * CELL;

  const canvas = document.getElementById('life');
  const ctx = canvas.getContext('2d');
  canvas.width = CANVAS_W;
  canvas.height = CANVAS_H;

  // Grid storage — two buffers for simultaneous update
  let grid, nextGrid;
  grid = Array.from({ length: H }, () => new Uint8Array(W));
  nextGrid = Array.from({ length: H }, () => new Uint8Array(W));

  window.life = { w: W, h: H };

  function get(x, y) {
    if (x < 0 || x >= W || y < 0 || y >= H) return 0;
    return grid[y][x];
  }

  function set(x, y, v) {
    if (x < 0 || x >= W || y < 0 || y >= H) return;
    grid[y][x] = !!v ? 1 : 0;
  }

  function step() {
    // Compute next generation simultaneously
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        let neighbors = 0;
        for (let dy = -1; dy <= 1; dy++) {
          for (let dx = -1; dx <= 1; dx++) {
            if (dx === 0 && dy === 0) continue;
            neighbors += get(x + dx, y + dy);
          }
        }
        const alive = grid[y][x];
        nextGrid[y][x] = (alive && (neighbors === 2 || neighbors === 3)) ||
                          (!alive && neighbors === 3) ? 1 : 0;
      }
    }
    // Swap buffers
    let tmp = grid;
    grid = nextGrid;
    nextGrid = tmp;

    draw();
    updateInfo();
  }

  function clear() {
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        grid[y][x] = 0;
      }
    }
    draw();
    updateInfo();
  }

  function randomize() {
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        grid[y][x] = Math.random() < 0.25 ? 1 : 0;
      }
    }
    draw();
    updateInfo();
  }

  function toggleCell(x, y) {
    set(x, y, !get(x, y));
    draw();
    updateInfo();
  }

  // Drawing
  const aliveColor = '#e94560';
  const deadColor = '#1a1a2e';
  const gridLineColor = 'rgba(255,255,255,0.08)';

  function draw() {
    ctx.fillStyle = deadColor;
    ctx.fillRect(0, 0, CANVAS_W, CANVAS_H);

    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        if (grid[y][x]) {
          ctx.fillStyle = aliveColor;
          ctx.fillRect(x * CELL + 1, y * CELL + 1, CELL - 2, CELL - 2);
        } else {
          ctx.strokeStyle = gridLineColor;
          ctx.strokeRect(x * CELL, y * CELL, CELL, CELL);
        }
      }
    }

    // Draw ghost of next generation (subtle)
    if (nextGrid !== grid) {
      for (let y = 0; y < H; y++) {
        for (let x = 0; x < W; x++) {
          if (nextGrid[y][x] && !grid[y][x]) {
            ctx.fillStyle = 'rgba(233,69,96,0.15)';
            ctx.fillRect(x * CELL + 1, y * CELL + 1, CELL - 2, CELL - 2);
          } else if (!nextGrid[y][x] && grid[y][x]) {
            ctx.fillStyle = 'rgba(233,69,96,0.15)';
            ctx.fillRect(x * CELL + 1, y * CELL + 1, CELL - 2, CELL - 2);
          }
        }
      }
    }
  }

  function updateInfo() {
    let alive = 0;
    for (let y = 0; y < H; y++) for (let x = 0; x < W; x++) if (grid[y][x]) alive++;
    document.getElementById('info').textContent = `Generation: ${generation} | Alive cells: ${alive}`;
  }

  let generation = 0;
  updateInfo();

  // Mouse interaction — click / drag toggles cells
  let isDrawing = false;
  function getCellPos(e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = CANVAS_W / rect.width;
    const scaleY = CANVAS_H / rect.height;
    const x = Math.floor(((e.clientX - rect.left) * scaleX) / CELL);
    const y = Math.floor(((e.clientY - rect.top) * scaleY) / CELL);
    return { x, y };
  }

  canvas.addEventListener('mousedown', (e) => { isDrawing = true; toggleCell(...getCellPos(e)); });
  canvas.addEventListener('mousemove', (e) => { if (isDrawing) toggleCell(...getCellPos(e)); });
  window.addEventListener('mouseup', () => { isDrawing = false; });

  // Buttons
  document.getElementById('step').addEventListener('click', step);
  document.getElementById('clear').addEventListener('click', clear);
  document.getElementById('random').addEventListener('click', randomize);

  let playing = false;
  let playInterval = null;
  const playBtn = document.getElementById('play');

  function startPlay() {
    if (playing) return;
    playing = true;
    playBtn.textContent = 'Pause ◀';
    playBtn.style.background = '#e94560';
    playInterval = setInterval(step, 120);
  }

  function stopPlay() {
    playing = false;
    if (playInterval) clearInterval(playInterval);
    playBtn.textContent = 'Play ▸';
    playBtn.style.background = '#0f3460';
  }

  playBtn.addEventListener('click', () => playing ? stopPlay() : startPlay());

  // Keyboard shortcuts
  document.addEventListener('keydown', (e) => {
    if (e.code === 'Space') { e.preventDefault(); playing ? stopPlay() : startPlay(); }
    else if (e.key === 's' || e.key === 'S') step();
    else if (e.key === 'r' || e.key === 'R') randomize();
    else if (e.key === 'c' || e.key === 'C') clear();
  });

})();
</script>
</body>
</html>
